import org.joda.time.DateTimeZone;

public class TestBug {
    public static void main(String[] args) {
        try {
            System.out.println("Testing forOffsetHoursMinutes(-2, 30):");
            DateTimeZone zone = DateTimeZone.forOffsetHoursMinutes(-2, 30);
            System.out.println("Result zone ID: " + zone.getID());
            System.out.println("Expected: -02:30");

            System.out.println("\nTesting forID(\"-02:30\"):");
            DateTimeZone expectedZone = DateTimeZone.forID("-02:30");
            System.out.println("Expected zone ID: " + expectedZone.getID());

            System.out.println("\nAre they equal? " + zone.equals(expectedZone));
            System.out.println("Are IDs equal? " + zone.getID().equals(expectedZone.getID()));

            System.out.println("\nTesting other cases:");
            System.out.println("forOffsetHoursMinutes(0, 0): " + DateTimeZone.forOffsetHoursMinutes(0, 0).getID());
            System.out.println("forOffsetHoursMinutes(2, 30): " + DateTimeZone.forOffsetHoursMinutes(2, 30).getID());
            System.out.println("forOffsetHoursMinutes(-2, 0): " + DateTimeZone.forOffsetHoursMinutes(-2, 0).getID());

        } catch (Exception e) {
            System.out.println("Exception: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

